import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Premium / quote — base item premiums
  it.todo("empty item list → premium 5 G (processing fee only)");
  it.todo("single plain sword → premium 100 + 5 = 105 G");
  it.todo("single plain amulet → premium 60 + 5 = 65 G");
  it.todo("single plain staff → premium 80 + 5 = 85 G");
  it.todo("single plain potion → premium 40 + 5 = 45 G");
  it.todo("two plain items sum their base premiums (sword + amulet → 165 G)");

  // Components and block-of-3
  it.todo("single rune component → premium 25 + 5 = 30 G");
  it.todo("2 runes → 50 G base premium → 55 G total");
  it.todo("3 runes → block applies, 60 G base → 65 G total");
  it.todo("4 runes → no block, 100 G base → 105 G total");
  it.todo("7 runes → 175 G base → 180 G total");
  it.todo("2 runes + 1 moonstone → 75 G base (no block, different types)");
  it.todo("3 runes + 3 moonstones → 120 G base (two separate blocks)");

  // Item-specific premium modifiers
  it.todo("cursed sword adds 50% surcharge on that item's base premium");
  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
  it.todo("enchantment exactly 5 triggers high-enchantment surcharge");
  it.todo("enchantment 4 does NOT trigger high-enchantment surcharge");
  it.todo("cursed AND highly enchanted item stacks both surcharges");

  // Policy-wide modifiers
  it.todo("first insurance adds 10% surcharge on policy base premium");
  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount");
  it.todo("exactly 2 years with MHPCO triggers loyalty discount");
  it.todo("follow-up contract (after first) gets 15% discount");

  // Integration: newcomer with cursed sword
  it.todo("newcomer with cursed sword (enchantment 3) → 165 G");

  // Integration: long-standing customer's second contract
  it.todo("3-year customer's 2nd contract, cursed sword enchantment 7 → 160 G");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor");

  // Errors during quote
  it.todo("unknown item type → CLI error (non-zero exit, stderr message)");

  // Claims — basic
  it.todo("standard sword damage 500 → payout 400 (deductible 100)");
  it.todo("damage to a rune (250 G), damage 200 → payout 100");
  it.todo("damage smaller than deductible → payout 0 (not negative)");

  // Special clauses
  it.todo("high enchantment (≥ 8) reimburses 50% of damage, then deductible");
  it.todo("dragon material gives full reimbursement");
  it.todo("dragon material + enchantment 9 → 50% rule wins, then deductible");
  it.todo("dragon material + enchantment 5 → full reimbursement (dragon only)");

  // Deductible per damage event
  it.todo("two damaged items in one incident → deductible applied per item");

  // Cap
  it.todo("policy cap = 2× insurance sum");
  it.todo("cap exhausted across successive claims");
  it.todo("multiple items of same type are insured separately");
  it.todo("damages array references more items of a type than insured → error");

  // Payout rounding
  it.todo("payout rounds down in MHPCO's favor");

  // Claim errors
  it.todo("claim references item not in policy → error");
  it.todo("negative damage amount → error");

  // CLI
  it.todo("CLI processes a multi-step scenario from stdin to stdout");
});

