const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };

const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const RUNE_BLOCK_OF_THREE = 60;

const sumItemPremiums = (items: Item[]): number => {
  const runeCount = items.filter((i) => i.type === "rune").length;
  if (runeCount === 3) return RUNE_BLOCK_OF_THREE;
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

const quote = ({ items }: Step): { premium: number } => ({
  premium: sumItemPremiums(items) + PROCESSING_FEE,
});

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quote) };
};

