const PROCESSING_FEE = 5;
const BLOCK_OF_THREE_SIZE = 3;
const BLOCK_OF_THREE_PREMIUM = 60;
const CURSED_SURCHARGE = 0.5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };

const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const groupByType = (items: Item[]): Map<string, number> =>
  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);

const componentsPremium = (items: Item[]): number =>
  Array.from(groupByType(items.filter(isComponent)))
    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);

const itemSurcharge = (item: Item): number =>
  item.cursed ? CURSED_SURCHARGE : 0;

const itemPremium = (item: Item): number =>
  basePremiumFor(item.type) * (1 + itemSurcharge(item));

const mainItemsPremium = (items: Item[]): number =>
  items.filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + itemPremium(item), 0);

const itemsPremium = (items: Item[]): number =>
  mainItemsPremium(items) + componentsPremium(items);

const quote = ({ items }: Step): { premium: number } => ({
  premium: itemsPremium(items) + PROCESSING_FEE,
});

export const runScenario = (input: unknown): unknown => {
  const { steps } = input as Scenario;
  return { results: steps.map(quote) };
};

