const PROCESSING_FEE = 5;
const BLOCK_OF_THREE_SIZE = 3;
const BLOCK_OF_THREE_PREMIUM = 60;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: Customer; steps: Step[] };

const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const isMainItem = (item: Item): boolean => !isComponent(item);

const groupByType = (items: Item[]): Map<string, number> =>
  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);

const componentsPremium = (items: Item[]): number =>
  Array.from(groupByType(items.filter(isComponent)))
    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);

const applySurcharge = (base: number, rate: number): number => base * (1 + rate);

const itemSurcharge = (item: Item): number =>
  surchargeWhen(item.cursed === true, CURSED_SURCHARGE) +
  surchargeWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);

const itemPremium = (item: Item): number =>
  applySurcharge(basePremiumFor(item.type), itemSurcharge(item));

const mainItemsPremium = (items: Item[]): number =>
  items.filter(isMainItem)
    .reduce((sum, item) => sum + itemPremium(item), 0);

const itemsPremium = (items: Item[]): number =>
  mainItemsPremium(items) + componentsPremium(items);

const policySurcharge = (customer: Customer): number =>
  surchargeWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE);

const FLOATING_POINT_EPSILON = 1e-9;

const roundUpInOurFavor = (amount: number): number =>
  Math.ceil(amount - FLOATING_POINT_EPSILON);

const quote = (customer: Customer) => ({ items }: Step): { premium: number } => ({
  premium: roundUpInOurFavor(applySurcharge(itemsPremium(items), policySurcharge(customer)) + PROCESSING_FEE),
});

export const runScenario = (input: unknown): unknown => {
  const { customer, steps } = input as Scenario;
  return { results: steps.map(quote(customer)) };
};

