     const BASE_PREMIUM: Record<string, number> = { sword:100, amulet:60, staff:80, potion:40, rune:25, moonstone:25 };
     const INSURANCE_VALUE: Record<string, number> = { sword:1000, amulet:600, staff:800, potion:400, rune:250, moonstone:250 };
     const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

     type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
     type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
     type Damage = { itemType: string; amount: number };
     type Incident = { cause: string; damages: Damage[] };
     type QuoteStep = { op: "quote"; items: Item[] };
     type ClaimStep = { op: "claim"; policy: number; incident: Incident };
     type Step = QuoteStep | ClaimStep;
     type Policy = { items: Item[]; cap: number };

     // Helpers:
     // basePremiumFor (throws on unknown), insuranceValueFor, lookupByType
     // isComponent, isMainItem, groupByType, componentGroupPremium, componentsPremium
     // isHighlyEnchanted (>= HIGH_ENCHANTMENT_THRESHOLD), rateWhen, itemRateAdjustment, itemPremium
     // PremiumBreakdown {base, withSurcharges}, addBreakdowns, mainItemBreakdown, componentsBreakdown, itemsBreakdown
     // isLongStanding, policyRateAdjustment, roundUpInOurFavor (with FLOATING_POINT_EPSILON 1e-9)
     // policyPremium = withSurcharges + base * policyRateAdjustment + PROCESSING_FEE
